// initialize Foundation javascript functionality
$(document).foundation();


$(document).ready( function () {

  // initialize datatables
  $('.dataTable').DataTable({
    paging: false,
    searching: false,
    info:false,
    "order": [],
    "scrollX": true
  });

  $('.dataTableSimple').DataTable({
    paging: false,
    searching: false,
    info:false,
    "order": [],
    "scrollX": true
  });

  $('.dataTableSimple tr').click(function() {
      var href = $(this).find("a").attr("href");
      if(href) {
          window.location = href;
      }
  });

  // auto load current page url into send to friend url input (without # and anything after it)
  $('#js-SendToFriendUrl').val(window.location.href.split('#')[0]);
  $('#js-SendToFriendTitle').val(document.title);

});
